    'subscribe.subscribeNow': 'Jetzt abonnieren',
    'subscribe.feature1': '✓ Wasserzeichen entfernen',
    'subscribe.feature2': '✓ Logos entfernen',
    'subscribe.feature3': '✓ Hochwertige Ergebnisse',
