    'copyright.title': 'Urheberrechtshinweis',
    'copyright.ownership': 'Urheberrechtseigentum',
    'copyright.ownershipText': 'Alle Inhalte auf dieser Website, einschließlich, aber nicht beschränkt auf Text, Grafiken, Logos, Bilder und Software, sind Eigentum von RemoveWatermark und durch Urheberrechtsgesetze geschützt.',
    'copyright.userContent': 'Benutzerinhalte',
    'copyright.userContentText': 'Sie behalten alle Rechte an Bildern, die Sie zu unserem Service hochladen. Durch die Nutzung unseres Services gewähren Sie uns eine eingeschränkte Lizenz zur Verarbeitung Ihrer Bilder ausschließlich zum Zweck der Bereitstellung des Services.',
    'copyright.prohibited': 'Verbotene Nutzungen',
    'copyright.prohibitedText': 'Sie dürfen nicht:',
    'copyright.prohibited1': 'Unsere urheberrechtlich geschützten Inhalte ohne Erlaubnis reproduzieren, verbreiten oder anzeigen',
    'copyright.prohibited2': 'Unsern Service nutzen, um Urheberrechte anderer zu verletzen',
