const LanguageContext = createContext<LanguageContextType | undefined>(undefined)

export function LanguageProvider({ children, lang: initialLang }: { children: React.ReactNode; lang?: string }) {
  // 有效的语言列表
  const validLanguages: Language[] = ['en', 'zh', 'ru', 'ar', 'de', 'ja', 'fr', 'es', 'pt', 'ko']
  
  console.log('[DEBUG LanguageProvider] initialLang:', initialLang)
  console.log('[DEBUG LanguageProvider] window.location.pathname:', typeof window !== 'undefined' ? window.location.pathname : 'undefined')
  
  // 确定初始语言
  const getInitialLanguage = (): Language => {
    if (initialLang && validLanguages.includes(initialLang as Language)) {
      console.log('[DEBUG LanguageProvider] Using initialLang:', initialLang)
      return initialLang as Language
    }
    console.log('[DEBUG LanguageProvider] Using default lang: en')
    return 'en'
  }
  
  const [language, setLanguageState] = useState<Language>(getInitialLanguage)
  console.log('[DEBUG LanguageProvider] language state:', language)

  // 监听客户端路由变化 - 使用 popstate 事件
  useEffect(() => {
    if (typeof window === 'undefined') return
    
    const handleRouteChange = () => {
      const path = window.location.pathname
      const pathParts = path.split('/').filter(Boolean)
      if (pathParts.length > 0 && validLanguages.includes(pathParts[0] as Language)) {
        const urlLang = pathParts[0] as Language
        setLanguageState(urlLang)
        localStorage.setItem('language', urlLang)
        document.cookie = `language=${urlLang};path=/;max-age=31536000`
      }
    }
    
    // 监听 popstate 事件
    window.addEventListener('popstate', handleRouteChange)
    
    return () => window.removeEventListener('popstate', handleRouteChange)
  }, [])

  const setLanguage = (newLang: Language) => {
    setLanguageState(newLang)
    localStorage.setItem('language', newLang)
    document.cookie = `language=${newLang};path=/;max-age=31536000`
  }

  const t = (key: string): string => {
    return translations[language][key] || key
  }

  return (
    <LanguageContext.Provider value={{ language, setLanguage, t }}>
      {children}
    </LanguageContext.Provider>
  )
}

export function useLanguage() {
  const context = useContext(LanguageContext)
  if (context === undefined) {
    throw new Error('useLanguage must be used within a LanguageProvider')
  }
  return context
}
